const rpRaw = $('Get the recently played tracks').all();
const recentlyPlayed = rpRaw.map(item => item.json);
const shortTerm = $('Fave Artist Short Term').first().json.items || [];
const mediumTerm = $('Fave Artist Medium Term').first().json.items || [];
const longTerm = $('Fave Artist Long Term').first().json.items || [];

const recentMap = {};
for (const track of recentlyPlayed) {
  const artist = track.track.artists[0];
  const playedAt = new Date(track.played_at);
  if (!recentMap[artist.id]) {
    recentMap[artist.id] = { last_played_at: playedAt, play_count: 0 };
  }
  if (playedAt > recentMap[artist.id].last_played_at) {
    recentMap[artist.id].last_played_at = playedAt;
  }
  recentMap[artist.id].play_count++;
}

function normalizeName(name) {
  return name
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/\s*[\(\[].*?[\)\]]\s*/g, '')
    .replace(/\bfeat\.?\b.*$/i, '')
    .replace(/\bft\.?\b.*$/i, '')
    .trim();
}

const artistMap = {};

function addArtist(artist, termKey, rank) {
  if (!artistMap[artist.id]) {
    artistMap[artist.id] = {
      id: artist.id,
      name: artist.name,
      name_normalized: normalizeName(artist.name),
      genres: artist.genres || [],
      short_term_rank: null,
      medium_term_rank: null,
      long_term_rank: null,
      last_played_at: null,
      days_since_played: 999,
      recent_play_count: 0,
    };
  }
  artistMap[artist.id][termKey] = rank;
}

shortTerm.forEach((a, i) => addArtist(a, 'short_term_rank', i + 1));
mediumTerm.forEach((a, i) => addArtist(a, 'medium_term_rank', i + 1));
longTerm.forEach((a, i) => addArtist(a, 'long_term_rank', i + 1));

const now = new Date();
for (const [id, data] of Object.entries(recentMap)) {
  if (artistMap[id]) {
    artistMap[id].last_played_at = data.last_played_at.toISOString();
    artistMap[id].days_since_played = Math.floor((now - data.last_played_at) / (1000 * 60 * 60 * 24));
    artistMap[id].recent_play_count = data.play_count;
  }
}

const artists = Object.values(artistMap).sort((a, b) => {
  const aRank = a.short_term_rank ?? a.medium_term_rank ?? a.long_term_rank ?? 999;
  const bRank = b.short_term_rank ?? b.medium_term_rank ?? b.long_term_rank ?? 999;
  return aRank - bRank;
});

return artists.map(a => ({ json: a }));

// Reset per-execution Ticketmaster match accumulator before building search windows.
const workflowStaticData = $getWorkflowStaticData('global');
workflowStaticData.ticketmasterMatchedConcerts = [];
workflowStaticData.ticketmasterSeenConcertKeys = [];

// Ticketmaster caps paging depth: page * size must be less than 1,000.
// Split the 6-month search into monthly windows and fetch pages 0-4 for each.
const MONTHS_AHEAD = 6;
const MAX_PAGES_PER_WINDOW = 5;

function toTmDate(date) {
  return date.toISOString().split('.')[0] + 'Z';
}

const now = new Date();
const end = new Date(now);
end.setMonth(end.getMonth() + MONTHS_AHEAD);

const windows = [];
let cursor = new Date(now);
while (cursor < end) {
  const windowStart = new Date(cursor);
  const windowEnd = new Date(cursor);
  windowEnd.setMonth(windowEnd.getMonth() + 1);
  if (windowEnd > end) windowEnd.setTime(end.getTime());

  for (let page = 0; page < MAX_PAGES_PER_WINDOW; page++) {
    windows.push({
      json: {
        page,
        startDateTime: toTmDate(windowStart),
        endDateTime: toTmDate(windowEnd),
      },
    });
  }

  cursor = windowEnd;
}

return windows;

// Get the Spotify artist profile from the Build Artist Profile node
const artists = $('Build Artist Profile').all().map(item => item.json);

// Match only the current compact Ticketmaster page.
// The loop stores only matched concerts, which keeps n8n Cloud memory low.
const inputItems = $input.all().map(item => item.json);
if (inputItems.every(item => item.__ticketmasterLoopControl)) {
  return [{ json: { __ticketmasterLoopControl: true } }];
}
const events = inputItems.filter(item => !item.__ticketmasterLoopControl);

// User location (Downtown Brooklyn) for haversine distance
const USER_LAT = 40.6928;
const USER_LNG = -73.9903;

function haversineMiles(lat1, lng1, lat2, lng2) {
  const R = 3958.8;
  const toRad = d => d * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLng = toRad(lng2 - lng1);
  const a = Math.sin(dLat / 2) ** 2
          + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLng / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

function normalizeName(name) {
  return String(name || '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/\s*[\(\[].*?[\)\]]\s*/g, '')
    .replace(/\bfeat\.?\b.*$/i, '')
    .replace(/\bft\.?\b.*$/i, '')
    .replace(/&/g, ' and ')
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
}

function levenshtein(a, b) {
  if (a === b) return 0;
  if (!a.length) return b.length;
  if (!b.length) return a.length;
  const dp = Array.from({ length: a.length + 1 }, () => new Array(b.length + 1).fill(0));
  for (let i = 0; i <= a.length; i++) dp[i][0] = i;
  for (let j = 0; j <= b.length; j++) dp[0][j] = j;
  for (let i = 1; i <= a.length; i++) {
    for (let j = 1; j <= b.length; j++) {
      dp[i][j] = a[i - 1] === b[j - 1]
        ? dp[i - 1][j - 1]
        : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
    }
  }
  return dp[a.length][b.length];
}

const artistByNormalized = {};
for (const a of artists) {
  artistByNormalized[a.name_normalized || normalizeName(a.name)] = a;
}

function findMatch(eventArtistName) {
  const normalized = normalizeName(eventArtistName);
  if (artistByNormalized[normalized]) return artistByNormalized[normalized];
  for (const a of artists) {
    const artistNormalized = a.name_normalized || normalizeName(a.name);
    if (normalized.length < 8 || artistNormalized.length < 8) continue;
    const dist = levenshtein(normalized, artistNormalized);
    const maxLen = Math.max(normalized.length, artistNormalized.length);
    if (dist <= 1 && dist / maxLen <= 0.15) return a;
  }
  return null;
}

const workflowStaticData = $getWorkflowStaticData('global');
if (!Array.isArray(workflowStaticData.ticketmasterMatchedConcerts)) workflowStaticData.ticketmasterMatchedConcerts = [];
if (!Array.isArray(workflowStaticData.ticketmasterSeenConcertKeys)) workflowStaticData.ticketmasterSeenConcertKeys = [];
const matched = [];
const seenConcertKeys = new Set(workflowStaticData.ticketmasterSeenConcertKeys);
for (const ev of events) {
  const attractions = ev.attractions || [];
  const headlinerName = attractions[0]?.name || ev.name || null;
  const venue = ev.venue || {};
  const venueLat = parseFloat(venue.latitude);
  const venueLng = parseFloat(venue.longitude);
  const distance = (Number.isFinite(venueLat) && Number.isFinite(venueLng))
    ? Math.round(haversineMiles(USER_LAT, USER_LNG, venueLat, venueLng) * 10) / 10
    : null;

  const matchesForEvent = [];
  const seenArtistIds = new Set();
  attractions.forEach((att, index) => {
    const artist = findMatch(att.name);
    if (!artist || seenArtistIds.has(artist.id)) return;
    seenArtistIds.add(artist.id);
    matchesForEvent.push({
      artist,
      matchedName: att.name,
      matchType: 'attraction',
      isOpener: index > 0,
    });
  });

  for (const match of matchesForEvent) {
    const matchedArtist = match.artist;
    const eventId = matchesForEvent.length > 1
      ? 'tm:' + ev.id + ':' + matchedArtist.id
      : 'tm:' + ev.id;
    const concertKey = [
      matchedArtist.id,
      ev.date,
      normalizeName(venue.name),
    ].join('|');
    if (seenConcertKeys.has(concertKey)) continue;
    seenConcertKeys.add(concertKey);

    matched.push({
      event_id: eventId,
      source: 'ticketmaster',
      artist_id: matchedArtist.id,
      artist_name: matchedArtist.name,
      artist_name_matched: match.matchedName,
      match_type: match.matchType,
      headliner_name: headlinerName,
      is_opener: match.isOpener,
      date: ev.date,
      venue_name: venue.name || null,
      venue_city: venue.city || null,
      venue_state: venue.state || null,
      venue_lat: Number.isFinite(venueLat) ? venueLat : null,
      venue_lng: Number.isFinite(venueLng) ? venueLng : null,
      distance_miles: distance,
      ticket_url: ev.url || null,
      price_min: ev.priceMin,
      price_max: ev.priceMax,
      on_sale: ev.status === 'onsale',
      days_since_played: matchedArtist.days_since_played,
      short_term_rank: matchedArtist.short_term_rank,
      medium_term_rank: matchedArtist.medium_term_rank,
      long_term_rank: matchedArtist.long_term_rank,
      recent_play_count: matchedArtist.recent_play_count,
    });
  }
}

if (matched.length > 0) {
  workflowStaticData.ticketmasterMatchedConcerts.push(...matched);
  workflowStaticData.ticketmasterSeenConcertKeys = Array.from(seenConcertKeys);
}

// Always return one item so the loop advances to the Wait node, even when a page has no matches.
return [{ json: { __ticketmasterLoopControl: true, matched_count: matched.length } }];

// Venue fit tier list — personalized to user preference for small/indie venues
const VENUE_TIERS = {
  // 10 points: DIY / intimate (~200-500 cap)
  "brooklyn made": 10,
