  "knockdown center": 7,
  "elsewhere": 7,
  "brooklyn paramount": 7,
  "le poisson rouge": 7,
  "(le) poisson rouge": 7,

  // 5 points: larger but acceptable (~1500-3000 cap)
  "brooklyn steel": 5,
  "webster hall": 5,
  "warsaw": 5,
  "kings theatre": 5,
  "beacon theatre": 5,
  "terminal 5": 5,
