  "barclays center": 1,
  "metlife stadium": 1,
  "prudential center": 1,
  "forest hills stadium": 1,
  "radio city music hall": 1,
};
const VENUE_DEFAULT = 3;

// Score one event
function scoreEvent(ev) {
  // --- Recency (max 30)
  let recency = 0;
  const dsp = ev.days_since_played;
  if (dsp === 0) recency = 30;
  else if (dsp <= 7) recency = 25;
  else if (dsp <= 30) recency = 15;
  else if (dsp <= 90) recency = 5;
  else recency = 0;

  // --- Frequency (max 25)
  const base = Math.min((ev.recent_play_count || 0) * 2, 15);
  let rank_bonus = 0;
  if (ev.short_term_rank != null) rank_bonus += ev.short_term_rank <= 10 ? 10 : 5;
  if (ev.medium_term_rank != null) rank_bonus += ev.medium_term_rank <= 10 ? 5 : 3;
  if (ev.long_term_rank != null) rank_bonus += ev.long_term_rank <= 10 ? 3 : 1;
  const frequency = Math.min(base + rank_bonus, 25);

  // --- Distance (max 20)
  let distance = 10;
  const d = ev.distance_miles;
  if (d != null) {
    if (d <= 5) distance = 20;
    else if (d <= 15) distance = 15;
    else if (d <= 30) distance = 10;
    else if (d <= 50) distance = 5;
    else distance = 0;
  }

  // --- Price (max 15)
  let price = 8;
  const p = ev.price_min;
  if (p != null) {
    if (p <= 50) price = 15;
    else if (p <= 100) price = 10;
    else if (p <= 200) price = 5;
    else price = 0;
  }

  // --- Venue fit (max 10)
  const venueKey = (ev.venue_name || "").toLowerCase().trim();
  const venue = VENUE_TIERS[venueKey] ?? VENUE_DEFAULT;

  const total = recency + frequency + distance + price + venue;

  return {
    ...ev,
    concert_score: total,
    score_breakdown: {
      recency,
      frequency,
      distance,
      price,
      venue,
    },
  };
}

// Score only the concerts accumulated during the Ticketmaster loop.
// The matcher writes compact matched concerts here per page, avoiding one huge event load.
const workflowStaticData = $getWorkflowStaticData('global');
const seen = new Set();
const events = (workflowStaticData.ticketmasterMatchedConcerts || [])
  .filter(ev => {
    const key = ev.event_id || [ev.artist_id, ev.date, ev.venue_name].join('|');
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
workflowStaticData.ticketmasterMatchedConcerts = [];
workflowStaticData.ticketmasterSeenConcertKeys = [];
const scored = events.map(scoreEvent);
scored.sort((a, b) => b.concert_score - a.concert_score);
return scored.map(s => ({ json: s }));

const THRESHOLD = 40;

// De-dupe against Notion (the durable source of truth) instead of workflow
// static data, which n8n Cloud wipes on re-save / version change.
// NOTE: verify the property paths in getProp() against the actual
