  const key = 'property_' + name.toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_+|_+$/g, '');
  let v = page[key];
  if (v === undefined) v = page[name];
  if (v === undefined && page.properties) v = page.properties[name];
  if (v == null) return undefined;
  if (typeof v === 'object') {
    if ('start' in v) return v.start;
    if ('checkbox' in v) return v.checkbox;
    if ('rich_text' in v) return (v.rich_text || []).map(t => t.plain_text || '').join('');
    if ('number' in v) return v.number;
    if ('name' in v) return v.name;
    return v;
  }
  return v;
}

