  const d = new Date(iso);
  return d.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric', year: 'numeric', timeZone: 'America/New_York' });
}
function calendarUrl(ev) {
  const title = encodeURIComponent(ev.artist_name + ' at ' + (ev.venue_name || 'TBD'));
  const loc = encodeURIComponent((ev.venue_name || '') + ', ' + (ev.venue_city || '') + ', ' + (ev.venue_state || ''));
  const details = encodeURIComponent('Score: ' + ev.concert_score + ' — ' + (ev.ticket_url || ''));

