      const mo = fmt(d.getUTCMonth() + 1);
      const dy = fmt(d.getUTCDate());
      const hr = fmt(d.getUTCHours());
      const mn = fmt(d.getUTCMinutes());
      startStr = `${yr}${mo}${dy}T${hr}${mn}00Z`;
      const endD = new Date(d.getTime() + 3 * 60 * 60 * 1000);
      endStr = `${endD.getUTCFullYear()}${fmt(endD.getUTCMonth()+1)}${fmt(endD.getUTCDate())}T${fmt(endD.getUTCHours())}${fmt(endD.getUTCMinutes())}00Z`;
