  html += '</p></div>';
}
return [{ json: { hasNew: true, count: newEvents.length, emailHtml: html, subject: '🎵 ' + newEvents.length + ' new concert alert' + (newEvents.length > 1 ? 's' : '') } }];

const CAL_THRESHOLD = 60;

