const scored = $('Attach Previews').all().map(item => item.json);
const above = scored.filter(ev => ev.concert_score >= CAL_THRESHOLD);
const newEvents = above.filter(ev => !calendaredIds.has(ev.event_id));

if (newEvents.length === 0) {
