const results = newEvents.map(ev => {
  let startDt, endDt;
  const raw = ev.date || '';
  const d = new Date(raw);

  if (raw.includes('T00:00:00') || raw.includes('T00:00:00Z')) {
    const utcDate = new Date(raw);
