    ''
  ];

  if (ev.setlist_preview && ev.setlist_preview !== 'No preview available.') {
    description.push('🎤 What to expect:', ev.setlist_preview, '');
  }

  description.push('Added automatically by Concert Intelligence Agent');

  return {
    json: {
      title,
      location,
      startDt,
      endDt,
      description: description.join('\n'),
      timeZone: 'America/New_York',
      event_id: ev.event_id
    }
  };
});

return results;

// Build create-vs-update routing using existing Notion pages as source of truth.
// Every matched event is emitted: brand-new ones are created, already-tracked
// ones are updated (keeps Score / Alerted / On Calendar current run to run).
// NOTE: verify getProp() paths against the real "Get Notion Pages" output.
function getProp(page, name) {
  // n8n's Notion node flattens props as property_<snake_case_name>;
  // dates come back as { start, end, time_zone }. Page id is at page.id.
  const key = 'property_' + name.toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_+|_+$/g, '');
  let v = page[key];
  if (v === undefined) v = page[name];
  if (v === undefined && page.properties) v = page.properties[name];
  if (v == null) return undefined;
  if (typeof v === 'object') {
    if ('start' in v) return v.start;
    if ('checkbox' in v) return v.checkbox;
    if ('rich_text' in v) return (v.rich_text || []).map(t => t.plain_text || '').join('');
    if ('number' in v) return v.number;
    if ('name' in v) return v.name;
    return v;
  }
  return v;
}

const existingPages = $('Get Notion Pages').all().map(i => i.json);
const byEventId = {};
for (const p of existingPages) {
  const eid = getProp(p, 'Event ID');
  if (!eid) continue;
  byEventId[eid] = { pageId: p.id, discovered: getProp(p, 'Discovered') };
}

const scored = $('Attach Previews').all().map(item => item.json);

function fixDate(raw) {
  if (!raw) return null;
  if (raw.includes('T00:00:00') || raw.includes('T00:00:00Z')) {
    const utcDate = new Date(raw);
    utcDate.setDate(utcDate.getDate() - 1);
    return utcDate.toISOString().slice(0, 10);
  }
  return raw.slice(0, 10);
}

function shortDate(ymd) {
  if (!ymd) return '';
  const parts = String(ymd).slice(0, 10).split('-').map(Number);
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  if (parts.length < 3 || !months[parts[1] - 1]) return '';
  return months[parts[1] - 1] + ' ' + parts[2] + ', ' + parts[0];
}
const results = scored.map(ev => {
  const baseTitle = ev.is_opener
    ? `${ev.artist_name} (opening for ${ev.headliner_name}) at ${ev.venue_name || 'TBD'}`
    : `${ev.artist_name} at ${ev.venue_name || 'TBD'}`;
  const dateLabel = shortDate(fixDate(ev.date));
  const title = dateLabel ? `${baseTitle} — ${dateLabel}` : baseTitle;

  const sb = ev.score_breakdown;
  const breakdown = `recency ${sb.recency} · freq ${sb.frequency} · dist ${sb.distance} · price ${sb.price} · venue ${sb.venue}`;
  const city = [ev.venue_city, ev.venue_state].filter(Boolean).join(', ');
  const today = new Date().toISOString().slice(0, 10);
  const preview = (ev.setlist_preview && ev.setlist_preview !== 'No preview available.') ? ev.setlist_preview : '';

  const existing = byEventId[ev.event_id];

  return {
    json: {
      operation: existing ? 'update' : 'create',
      pageId: existing ? existing.pageId : '',
      concert: title,
      date: fixDate(ev.date),
      score: ev.concert_score,
      artist: ev.artist_name,
      venue: ev.venue_name || '',
      city,
      distance: ev.distance_miles,
      price: ev.price_min,
      breakdown,
      openerFor: ev.is_opener ? ev.headliner_name : '',
      tickets: ev.ticket_url || '',
      alerted: ev.concert_score >= 40,
      onCalendar: ev.concert_score >= 60,
      eventId: ev.event_id,
      discovered: (existing && existing.discovered) ? String(existing.discovered).slice(0, 10) : today,
      preview
    }
  };
});

return results;

const CACHE_TTL_DAYS = 30;
const staticData = $getWorkflowStaticData('global');
if (!staticData.setlistPreviews) staticData.setlistPreviews = {};

const events = $input.all().map(item => item.json);
staticData._scoredEvents = events; // stash for the end

function isCacheFresh(entry) {
  if (!entry || !entry.generatedAt) return false;
  const age = (Date.now() - new Date(entry.generatedAt).getTime()) / (1000 * 60 * 60 * 24);
  return age < CACHE_TTL_DAYS;
}

// Unique artists that need a fresh preview
const seen = {};
const artists = [];
for (const ev of events) {
  if (seen[ev.artist_id]) continue;
  seen[ev.artist_id] = true;

  if (isCacheFresh(staticData.setlistPreviews[ev.artist_id])) continue; // skip cached

  artists.push({
    json: {
      artist_id: ev.artist_id,
      artist_name: ev.artist_name,
      is_opener: ev.is_opener,
      headliner_name: ev.headliner_name
    }
  });
}

return artists;

// Run Once for Each Item mode
const sfData = $json; // the Setlist.fm response for THIS artist
const artist = $('Setlist Prep').all()[$itemIndex].json;

const setlists = (sfData.setlist || []).slice(0, 5);

let prompt;
if (setlists.length === 0) {
  prompt = `Write exactly this sentence and nothing else: "No recent setlist data available for ${artist.artist_name}."`;
} else {
  const formatted = setlists.map((sl, i) => {
    const date = sl.eventDate || 'unknown date';
    const venue = sl.venue?.name || 'unknown venue';
    const sets = sl.sets?.set || [];
    const songs = sets.map(s => {
      const setName = s.name || (s.encore ? 'Encore' : 'Main Set');
      return `  ${setName}: ${(s.song || []).map(x => x.name).filter(Boolean).join(', ')}`;
    }).join('\n');
    return `Show ${i + 1} (${date}, ${venue}):\n${songs}`;
  }).join('\n\n');

  const openerNote = artist.is_opener
    ? `\nNote: this artist is opening for ${artist.headliner_name}, so expect a shorter set (30-45 min).`
    : '';

  prompt = `You are a concert preview writer. Given these recent setlists for ${artist.artist_name}, write a 2-3 sentence preview of what to expect at their upcoming show. Focus on set length, key songs, and notable production. Be specific about song names. Concise and enthusiastic, like a knowledgeable friend. Output ONLY the preview itself with no preamble — start directly with the description.${openerNote}\n\nRecent setlists:\n${formatted}`;
}

return { json: { artist_id: artist.artist_id, artist_name: artist.artist_name, prompt } };

const staticData = $getWorkflowStaticData('global');
const prompts = $('Build Prompt').all();
const claudeOut = $input.all();

for (let i = 0; i < prompts.length; i++) {
  const aid = prompts[i].json.artist_id;
