// Reduce each Ticketmaster page to compact event records before the loop stores output.
// This keeps the later matching node from loading full raw Ticketmaster responses.
const response = $input.first().json;
const events = response._embedded?.events || [];
if (events.length === 0) {
  return [{ json: { __ticketmasterLoopControl: true, reason: 'empty_ticketmaster_page' } }];
}

function compactEvent(ev) {
  return {
    id: ev.id,
    name: ev.name || null,
    url: ev.url || null,
    date: ev.dates?.start?.dateTime || ev.dates?.start?.localDate || null,
    status: ev.dates?.status?.code || null,
    attractions: (ev._embedded?.attractions || []).map(a => ({ name: a.name || null })).filter(a => a.name),
    venue: (() => {
      const venue = ev._embedded?.venues?.[0] || {};
      return {
        name: venue.name || null,
        city: venue.city?.name || null,
        state: venue.state?.stateCode || null,
        latitude: venue.location?.latitude || null,
        longitude: venue.location?.longitude || null,
      };
    })(),
    priceMin: ev.priceRanges?.[0]?.min ?? null,
    priceMax: ev.priceRanges?.[0]?.max ?? null,
  };
}

return events.map(ev => ({ json: compactEvent(ev) }));
